// In websocket.adapter.ts, add token update listener:
private setupTokenRefreshListener(): void {
  this._authService.onTokenRefreshed$.subscribe(() => {
    if (this.isConnected) {
      this.logger.info('Token refreshed, reconnecting WebSocket');

      // Store current state
      const currentUrl = this._url;

      // Disconnect old connection
      this.disconnect();

      // Reconnect with new token
      if (currentUrl) {
        // Remove old token from URL
        const baseUrl = currentUrl.split('?')[0];
        this.connect(baseUrl).subscribe();
      }
    }
  });
}
