```typescript
private initiateTMISAMLLogin(provider: SAMLProviderInfo, returnUrl?: string): void {
  // Generate unique RelayState
  const relayState = this.generateRandomState(returnUrl);

  // Store RelayState for validation on callback
  sessionStorage.setItem('saml_relay_state', relayState);
  sessionStorage.setItem('saml_provider_id', provider.id);

  // Include RelayState in SAML request
  const authUrl = `${provider.auth_url}${separator}RelayState=${encodeURIComponent(relayState)}`;

  window.location.href = authUrl;
}

// On SAML callback:
private handleSAMLCallback(response: SAMLResponse): void {
  const storedRelayState = sessionStorage.getItem('saml_relay_state');
  const storedProviderId = sessionStorage.getItem('saml_provider_id');

  if (response.RelayState !== storedRelayState) {
    this.logger.error('SAML RelayState mismatch');
    // Handle error
  }

  // Clear stored values
  sessionStorage.removeItem('saml_relay_state');
  sessionStorage.removeItem('saml_provider_id');
}
